#include<bits/stdc++.h> 
using namespace std;
const int N=100005,inf=0x3f3f3f3f;
int n,b,a[25],dp[N],lst=1,ans;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>b;
	for(int i=1;i<=b;i++)
	{
		cin>>a[i];
	}
	memset(dp,0x3f,sizeof(dp));
	dp[0]=0;
	for(int i=1;i<=b;i++)
	{
		for(int j=a[i];j<=N-5;j++)
		{
			dp[j]=min(dp[j],dp[j-a[i]]+1);
		}
	}
//	for(int i=0;i<=20;i++) cout<<i<<"  : "<<dp[i]<<"\n";
	for(int i=1;i<=n;i++)
	{
		int x;
		cin>>x;
		int t=x-lst+1;
		if(t<0)
		{
			cout<<-1;
			return 0;
		}
		ans+=dp[t];
//		cout<<t<<"  ";
		if(dp[t]>=inf/2)
		{
			cout<<-1;
			return 0;
		}
		lst=max(1,x);
	}
	cout<<ans;
	return 0;
}
